import { useEffect, useMemo, useRef, useState } from "react";
import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import api from "@/api/app/client";
import { getApiErrorMessage } from "@/api/app/apiError";
import {
  Plus,
  Edit2,
  Trash2,
  Camera,
  Globe,
  Building2,
  Mail,
  CreditCard,
  Briefcase,
  MapPin,
  Loader2
} from "lucide-react";
import { CustomerFormDialog } from "@/features/customers/components/CustomerFormDialog";
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import { Button } from "@/shadcn/components/ui/button";
import { getAuthorizedFileUrl, cleanupBlobUrl } from "@/utils/fileUtils";
import { uploadService } from "@/api/uploadService";
import type { Customer } from "@/types/customer";
import type { Project } from "@/types/project";

const extractList = (res: any): any[] => {
  const data = res?.data || res?.items || res;
  return Array.isArray(data) ? data : [];
};

const buildCustomerPayload = (data: Record<string, any>, isEditMode: boolean, editData: Customer | null) => {
  const customerStatusMap: Record<string, number> = { active: 0, inactive: 1 };
  const getVal = (val: any, map: Record<string, number>, fallback: number) => {
    if (val === undefined || val === null || val === "") return fallback;
    const n = Number(val);
    if (!isNaN(n)) return n;
    return map[String(val).toLowerCase()] ?? fallback;
  };

  const raw = {
    ...data,
    LogoFileId: isEditMode && editData ? (editData as Customer).logoFileId : (data.LogoFileId || null),
    Status: getVal(data.Status ?? data.status, customerStatusMap, 0),
  };

  const payload: Record<string, any> = {};
  Object.keys(raw).forEach(key => { if (key[0] === key[0].toUpperCase()) payload[key] = (raw as Record<string, any>)[key]; });
  return payload;
};

const buildProjectPayload = (data: Record<string, any>, isEditMode: boolean, editData: Project | null, selectedCustomerId: string) => {
  const typeMap: Record<string, number> = { internal: 0, customer: 1 };
  const statusMap: Record<string, number> = { planning: 0, active: 1, "on hold": 2, completed: 3, cancelled: 4 };
  const getVal = (val: any, map: Record<string, number>, fallback: number) => {
    if (val === undefined || val === null || val === "") return fallback;
    const n = Number(val);
    if (!isNaN(n)) return n;
    return map[String(val).toLowerCase()] ?? fallback;
  };

  const raw = {
    ...data,
    CustomerId: isEditMode ? (editData as Project).customerId : selectedCustomerId,
    Type: getVal(data.Type ?? data.type, typeMap, 0),
    Status: getVal(data.Status ?? data.status, statusMap, 0),
  };

  const payload: Record<string, any> = {};
  Object.keys(raw).forEach(key => { if (key[0] === key[0].toUpperCase()) payload[key] = (raw as Record<string, any>)[key]; });
  return payload;
};

const Customers = () => {
  const queryClient = useQueryClient();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [logoBlobUrls, setLogoBlobUrls] = useState<Record<string, { url: string; fileId: string }>>({});
  const [showForm, setShowForm] = useState(false);
  const [formType, setFormType] = useState<"CustomerInputDTO" | "ProjectInputDTO" | "">();
  const [selectedCustomerId, setSelectedCustomerId] = useState("");
  const [editData, setEditData] = useState<Customer | Project | null>(null);
  const [isEditMode, setIsEditMode] = useState(false);
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [itemToDelete, setItemToDelete] = useState<{ id: string; name: string; type: "Customer" | "Project"; customerId?: string } | null>(null);

  // ── Queries ────────────────────────────────────────────────────────────────

  const { data: customers = [], isLoading } = useQuery<Customer[]>({
    queryKey: ["customers"],
    queryFn: () => api.get("/customers").then(r => extractList(r.data)),
  });

  const projectQueries = useQueries({
    queries: customers.map(c => ({
      queryKey: ["customers", c.id, "projects"],
      queryFn: () => api.get(`/customers/${c.id}/projects`).then(r => extractList(r.data) as Project[]),
    })),
  });

  const projectsMap = useMemo(() => {
    return customers.reduce((acc, c, i) => {
      acc[c.id] = projectQueries[i]?.data ?? [];
      return acc;
    }, {} as Record<string, Project[]>);
  }, [customers, projectQueries]);

  // ── Logo blob URL management (side effect, stays as local state) ───────────

  useEffect(() => {
    const fetchLogos = async () => {
      const updates: Record<string, { url: string; fileId: string }> = {};
      for (const c of customers) {
        if (c.logoFileId) {
          const current = logoBlobUrls[c.id];
          if (!current || current.fileId !== c.logoFileId) {
            if (current?.url) cleanupBlobUrl(current.url);
            const blobUrl = await getAuthorizedFileUrl(c.logoFileId);
            if (blobUrl) updates[c.id] = { url: blobUrl, fileId: c.logoFileId };
          }
        }
      }
      if (Object.keys(updates).length > 0) {
        setLogoBlobUrls(prev => ({ ...prev, ...updates }));
      }
    };
    if (customers.length > 0) fetchLogos();
  }, [customers]);

  useEffect(() => {
    return () => { Object.values(logoBlobUrls).forEach(item => cleanupBlobUrl(item.url)); };
  }, []);

  // ── Mutations ──────────────────────────────────────────────────────────────

  const createCustomerMutation = useMutation({
    mutationFn: (payload: Record<string, any>) => api.post("/customers", payload),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["customers"] });
      setShowForm(false);
      toast.success("Customer created");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to create customer")),
  });

  const updateCustomerMutation = useMutation({
    mutationFn: ({ id, payload }: { id: string; payload: Record<string, any> }) =>
      api.put(`/customers/${id}`, payload),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["customers"] });
      setShowForm(false);
      toast.success("Customer updated");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to update customer")),
  });

  const deleteCustomerMutation = useMutation({
    mutationFn: (id: string) => api.delete(`/customers/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["customers"] });
      setItemToDelete(null);
      toast.success("Customer deleted");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Delete failed")),
  });

  const createProjectMutation = useMutation({
    mutationFn: ({ customerId, payload }: { customerId: string; payload: Record<string, any> }) =>
      api.post("/projects", payload).then(() => customerId),
    onSuccess: (customerId) => {
      queryClient.invalidateQueries({ queryKey: ["customers", customerId, "projects"] });
      setShowForm(false);
      toast.success("Project created");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to create project")),
  });

  const updateProjectMutation = useMutation({
    mutationFn: ({ id, customerId, payload }: { id: string; customerId: string; payload: Record<string, any> }) =>
      api.put(`/projects/${id}`, payload).then(() => customerId),
    onSuccess: (customerId) => {
      queryClient.invalidateQueries({ queryKey: ["customers", customerId, "projects"] });
      setShowForm(false);
      toast.success("Project updated");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to update project")),
  });

  const deleteProjectMutation = useMutation({
    mutationFn: ({ id, customerId }: { id: string; customerId: string }) =>
      api.delete(`/projects/${id}`).then(() => customerId),
    onSuccess: (customerId) => {
      queryClient.invalidateQueries({ queryKey: ["customers", customerId, "projects"] });
      setItemToDelete(null);
      toast.success("Project deleted");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Delete failed")),
  });

  // ── Handlers ───────────────────────────────────────────────────────────────

  const handleFormSubmit = (data: Record<string, any>) => {
    if (formType === "CustomerInputDTO") {
      const payload = buildCustomerPayload(data, isEditMode, editData as Customer | null);
      if (isEditMode && editData?.id) {
        updateCustomerMutation.mutate({ id: editData.id, payload });
      } else {
        createCustomerMutation.mutate(payload);
      }
    } else if (formType === "ProjectInputDTO") {
      const payload = buildProjectPayload(data, isEditMode, editData as Project | null, selectedCustomerId);
      if (isEditMode && editData?.id) {
        updateProjectMutation.mutate({ id: editData.id, customerId: payload.CustomerId, payload });
      } else {
        createProjectMutation.mutate({ customerId: payload.CustomerId, payload });
      }
    }
  };

  const handleDeleteItem = (id: string, name: string, type: "Customer" | "Project", customerId?: string) => {
    setItemToDelete({ id, name, type, customerId });
  };

  const confirmDelete = () => {
    if (!itemToDelete) return;
    if (itemToDelete.type === "Customer") {
      deleteCustomerMutation.mutate(itemToDelete.id);
    } else {
      deleteProjectMutation.mutate({ id: itemToDelete.id, customerId: itemToDelete.customerId! });
    }
  };

  const handleLogoUpload = async (customerId: string, file: File) => {
    setUploadingId(customerId);
    try {
      const uploadedFile = await uploadService.upload("/files", file);
      const customer = customers.find(c => c.id === customerId);
      if (!customer) return;

      const payload = {
        Name: customer.name,
        Website: customer.website,
        Industry: customer.industry,
        Notes: customer.notes,
        ContactsInfo: customer.contactsInfo,
        PaymentNotes: customer.paymentNotes,
        RegisteredAddress: customer.registeredAddress,
        Status: typeof customer.status === "string"
          ? (customer.status.toLowerCase() === "active" ? 0 : 1)
          : customer.status,
        LogoFileId: uploadedFile.id || uploadedFile,
      };

      await api.put(`/customers/${customerId}`, payload);
      queryClient.invalidateQueries({ queryKey: ["customers"] });
      toast.success("Logo updated");
    } catch (err) {
      toast.error(getApiErrorMessage(err, "Upload failed"));
    } finally {
      setUploadingId(null);
    }
  };

  // ── Helpers ────────────────────────────────────────────────────────────────

  const formatDate = (date: string) => {
    if (!date) return "N/A";
    return new Date(date).toLocaleDateString(undefined, { year: "numeric", month: "short", day: "numeric" });
  };

  const getProjectStatusBadge = (status: number | string) => {
    const s = String(status).toLowerCase();
    const baseClass = "px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider";
    if (s === "1" || s === "active") return <span className={`${baseClass} bg-emerald-100 dark:bg-emerald-950/40 text-emerald-700 dark:text-emerald-400`}>Active</span>;
    if (s === "2" || s === "on hold") return <span className={`${baseClass} bg-amber-100 dark:bg-amber-950/40 text-amber-700 dark:text-amber-400`}>On Hold</span>;
    if (s === "3" || s === "completed") return <span className={`${baseClass} bg-primary/10 text-primary`}>Completed</span>;
    if (s === "4" || s === "cancelled") return <span className={`${baseClass} bg-destructive/10 text-destructive`}>Cancelled</span>;
    return <span className={`${baseClass} bg-muted text-muted-foreground`}>Planning</span>;
  };

  const isFormSubmitting = createCustomerMutation.isPending || updateCustomerMutation.isPending
    || createProjectMutation.isPending || updateProjectMutation.isPending;

  const isDeleting = deleteCustomerMutation.isPending || deleteProjectMutation.isPending;

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div className="page-wrapper">
      <div className="page-header">
        <div>
          <h1 className="page-title">Customers &amp; Projects</h1>
          <p className="page-subtitle">Enterprise materials &amp; account registry</p>
        </div>
        <PermissionGate permission={PERMISSIONS.Customer.Create} mode="disable">
          <Button onClick={() => { setFormType("CustomerInputDTO"); setIsEditMode(false); setEditData(null); setShowForm(true); }}>
            <Plus size={16} /> Add Customer
          </Button>
        </PermissionGate>
      </div>

      {isLoading && customers.length === 0 ? (
        <div className="flex justify-center py-20"><Loader2 className="w-8 h-8 animate-spin text-primary" /></div>
      ) : customers.length === 0 ? (
        <div className="text-center py-20 bg-card rounded-lg border border-border">
          <Building2 className="w-12 h-12 mx-auto text-muted-foreground/30 mb-4" />
          <h3 className="text-base font-semibold text-foreground">No Customers Found</h3>
          <p className="text-muted-foreground text-sm mt-1">Start by adding your first enterprise client.</p>
        </div>
      ) : (
        <div className="space-y-8">
          {customers.map((c) => (
            <div key={c.id} className="space-y-4">
              {/* Customer Profile Card */}
              <div className="bg-card rounded-lg shadow-sm border border-border overflow-hidden">
                <div className="flex flex-col lg:flex-row">
                  {/* Logo Section */}
                  <div className="w-full lg:w-72 bg-muted/30 p-8 flex flex-col items-center justify-center border-b lg:border-b-0 lg:border-r border-border relative">
                    <div className="w-32 h-32 rounded-2xl bg-card shadow-sm flex items-center justify-center overflow-hidden border border-border relative">
                      {c.logoFileId && logoBlobUrls[c.id]?.url ? (
                        <img src={logoBlobUrls[c.id].url} alt={c.name} className="w-full h-full object-cover transition-transform duration-500" />
                      ) : (
                        <Building2 className="w-12 h-12 text-muted-foreground/30" />
                      )}
                      {uploadingId === c.id && (
                        <div className="absolute inset-0 bg-card/80 flex items-center justify-center z-20">
                          <Loader2 className="w-6 h-6 animate-spin text-primary" />
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="flex-1 p-6">
                    <div className="flex justify-between items-start">
                      <div>
                        <div className="flex items-center gap-3">
                          <h2 className="text-lg font-bold text-foreground">{c.name}</h2>
                          <span className={`px-2 py-0.5 rounded text-[11px] font-semibold ${
                            String(c.status).toLowerCase() === "active" || c.status === 0
                              ? "bg-emerald-100 dark:bg-emerald-950/40 text-emerald-700 dark:text-emerald-400"
                              : "bg-destructive/10 text-destructive"
                          }`}>
                            {String(c.status).toLowerCase() === "active" || c.status === 0 ? "Active" : "Inactive"}
                          </span>
                        </div>
                        <div className="flex items-center gap-6 mt-3">
                          {c.website && (
                            <a href={`https://${c.website}`} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 text-xs text-primary hover:underline">
                              <Globe size={13} /> {c.website}
                            </a>
                          )}
                          {c.industry && (
                            <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
                              <Briefcase size={13} /> {c.industry}
                            </span>
                          )}
                        </div>
                      </div>
                      <div className="flex gap-2">
                        <PermissionGate permission={PERMISSIONS.Customer.Update} mode="disable">
                          <button
                            onClick={() => { setSelectedCustomerId(c.id); fileInputRef.current?.click(); }}
                            className="p-2 text-muted-foreground hover:text-primary hover:bg-muted rounded-lg transition-all"
                            title="Upload Logo"
                          >
                            <Camera size={16} />
                          </button>
                        </PermissionGate>
                        <PermissionGate permission={PERMISSIONS.Customer.Update} mode="disable">
                          <button
                            onClick={() => { setFormType("CustomerInputDTO"); setIsEditMode(true); setEditData(c); setShowForm(true); }}
                            className="p-2 text-muted-foreground hover:text-primary hover:bg-muted rounded-lg transition-all"
                            title="Edit Customer"
                          >
                            <Edit2 size={16} />
                          </button>
                        </PermissionGate>
                        <PermissionGate permission={PERMISSIONS.Customer.Delete} mode="disable">
                          <button
                            onClick={() => handleDeleteItem(c.id, c.name, "Customer")}
                            className="p-2 text-muted-foreground hover:text-destructive hover:bg-destructive/10 rounded-lg transition-all"
                            title="Delete Customer"
                          >
                            <Trash2 size={16} />
                          </button>
                        </PermissionGate>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-8">
                      <div className="space-y-4">
                        <div className="flex items-start gap-3">
                          <MapPin size={16} className="text-muted-foreground mt-1 shrink-0" />
                          <div className="text-xs font-bold text-muted-foreground leading-relaxed">
                            {c.registeredAddress ? (
                              <>
                                {(c.registeredAddress.firstName || c.registeredAddress.lastName) && (
                                  <p className="text-foreground mb-0.5">{c.registeredAddress.firstName} {c.registeredAddress.lastName}</p>
                                )}
                                {c.registeredAddress.addressLine && <p className={!c.registeredAddress.firstName && !c.registeredAddress.lastName ? "text-foreground mb-0.5" : ""}>{c.registeredAddress.addressLine}</p>}
                                <p>{c.registeredAddress.city}{c.registeredAddress.state && `, ${c.registeredAddress.state}`} {c.registeredAddress.zipCode}</p>
                                <p>{c.registeredAddress.country}</p>
                              </>
                            ) : "No address recorded"}
                          </div>
                        </div>
                      </div>
                      <div className="bg-muted/50 rounded-2xl p-4 space-y-3">
                        <div className="flex items-center justify-between">
                          <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest flex items-center gap-2"><Mail size={12} /> Contacts</span>
                          <span className="text-xs font-bold text-foreground">{c.contactsInfo || "N/A"}</span>
                        </div>
                        <div className="flex items-center justify-between">
                          <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest flex items-center gap-2"><CreditCard size={12} /> Billing</span>
                          <span className="text-xs font-bold text-foreground">{c.paymentNotes || "Standard"}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Projects Table Section */}
              <div className="bg-card rounded-lg shadow-sm border border-border overflow-hidden">
                <div className="px-6 py-4 border-b border-border flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Briefcase size={16} className="text-primary" />
                    <h3 className="section-card-title">Project Portfolio</h3>
                  </div>
                  <PermissionGate permission={PERMISSIONS.Project.Create} mode="disable">
                    <Button size="sm" onClick={() => { setFormType("ProjectInputDTO"); setSelectedCustomerId(c.id); setIsEditMode(false); setEditData(null); setShowForm(true); }}>
                      <Plus size={14} /> New Project
                    </Button>
                  </PermissionGate>
                </div>

                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-muted-foreground border-b border-border">
                      {["Project Name", "Project Code", "Type", "Status", "Start", "End", "Actions"].map(h => (
                        <th key={h} className={`py-3 px-4 font-semibold text-left uppercase tracking-wider text-[10px] ${h === "Actions" ? "text-center" : ""}`}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {(projectsMap[c.id] || []).length === 0 ? (
                      <tr><td colSpan={7} className="py-8 text-center text-[10px] font-black text-muted-foreground uppercase tracking-widest">No active projects</td></tr>
                    ) : (projectsMap[c.id] || []).map((p) => (
                      <tr key={p.id} className="border-b border-border/30 hover:bg-muted/20 transition-colors">
                        <td className="py-3 px-4 font-medium text-foreground">{p.name}</td>
                        <td className="py-3 px-4 text-muted-foreground font-mono text-xs">{p.code}</td>
                        <td className="py-3 px-4 text-foreground">{p.type || "-"}</td>
                        <td className="py-3 px-4">{getProjectStatusBadge(p.status)}</td>
                        <td className="py-3 px-4 text-muted-foreground text-xs">{p.startDate ? formatDate(p.startDate) : "-"}</td>
                        <td className="py-3 px-4 text-muted-foreground text-xs">{p.endDate ? formatDate(p.endDate) : "-"}</td>
                        <td className="py-3 px-4 text-center space-x-2">
                          <button
                            onClick={() => { setFormType("ProjectInputDTO"); setSelectedCustomerId(c.id); setIsEditMode(true); setEditData(p); setShowForm(true); }}
                            className="text-primary hover:text-primary/80 text-sm font-medium"
                          >
                            Edit
                          </button>
                          <button
                            onClick={() => handleDeleteItem(p.id, p.name, "Project", c.id)}
                            className="text-destructive hover:text-destructive/80 text-sm font-medium"
                          >
                            Delete
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          ))}
        </div>
      )}

      <CustomerFormDialog
        open={showForm}
        onClose={() => setShowForm(false)}
        formType={formType ?? ""}
        isEditMode={isEditMode}
        editData={editData}
        onSubmit={handleFormSubmit}
        isSubmitting={isFormSubmitting}
      />

      <input
        type="file"
        ref={fileInputRef}
        className="hidden"
        accept="image/*"
        onChange={(e) => {
          const file = e.target.files?.[0];
          if (file && selectedCustomerId) handleLogoUpload(selectedCustomerId, file);
          e.target.value = "";
        }}
      />

      {itemToDelete && (
        <HarmonyAlertDialog
          open={!!itemToDelete}
          onOpenChange={(open) => { if (!open) setItemToDelete(null); }}
          variant="danger"
          title={`Delete ${itemToDelete.type}`}
          description={`This will permanently remove "${itemToDelete.name}". This action cannot be undone.`}
          actionLabel="Permanently Delete"
          onAction={confirmDelete}
          isActioning={isDeleting}
        />
      )}
    </div>
  );
};

export default Customers;
